
import csv
import io
import random
import uuid

def generate_csv_content(num_rows: int) -> str:
    """
    Generates a CSV string with random product definitions.
    Format matches the project requirement:
    #Nazwa;Id;Zdjecie;TempMin;TempMax;Waga;SzerokoscMm;WysokoscMm;GlebokoscMm;Komentarz;TerminWaznosciDni;CzyNiebezpieczny
    """
    output = io.StringIO()
    # Add comment lines as per spec
    output.write("#Linie zaczynające się od znaku '#' oznaczają komentarz i powinny być ignorowane.\n")
    output.write("#Nazwa;Id;Zdjecie;TempMin;TempMax;Waga;SzerokoscMm;WysokoscMm;GlebokoscMm;Komentarz;TerminWaznosciDni;CzyNiebezpieczny\n")
    
    writer = csv.writer(output, delimiter=';', lineterminator='\n')
    
    for i in range(num_rows):
        name = f"Produkt_Perf_{i}_{uuid.uuid4().hex[:6]}"
        barcode = f"BAR{uuid.uuid4().hex[:10].upper()}"
        photo = ""
        temp_min = random.randint(-10, 15)
        temp_max = temp_min + random.randint(5, 20)
        weight = round(random.uniform(0.1, 50.0), 2)
        width = random.randint(10, 500)
        height = random.randint(10, 500)
        depth = random.randint(10, 500)
        comment = "Generated by Locust"
        expiry_days = random.randint(30, 365)
        is_dangerous = "TRUE" if random.random() < 0.05 else "FALSE"
        
        writer.writerow([
            name,
            barcode,
            photo,
            temp_min,
            temp_max,
            weight,
            width,
            height,
            depth,
            comment,
            expiry_days,
            is_dangerous
        ])
        
    return output.getvalue()

import base64

def generate_dummy_image():
    """
    Generates a valid small JPG image in memory (1x1 pixel).
    Uses a known valid Base64 string to avoid byte literal issues.
    """
    # 1x1 pixel white JPEG
    base64_jpg = ""
    return base64.b64decode(base64_jpg)
